OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page



//   if( IsProject() == 0 )    int textMode = 0;

   int textMode = 0;



   char patyk1=255;

   char patyk2=255;

   char chrust=0;                  //liczba czesci na drodze

   char woz=0;                     //0-woz jedzie, 255-woz stoi

   Panorama_Holder.OpenPanorama(0);

   Panorama_Holder.SetHorizontalAngle(90);

   Sound_Holder.PlayDSound(4);



   LoadGroup("Cursors.grp");

   SetCursor(0);



//#############################################################################

   int toolbar=0;

   int toolbarCase=0;

   int toolbarPhase=0;

   int txtHotSpotOn=0;

   int playStatus=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

   SetTextMode();

//############################################################################





   FadeScreen(1,1000);

   if(textMode==0)

   {

      Panorama_Holder.GoRight(2);

      Sound_Holder.PlayDSound(0);

   }

   else

   {   

      Sprite_Holder.StopAnimation(0);

      Sprite_Holder.StopAnimation(1);

   }

   Sprite_Holder.SynchronizeTimers();

//   SetTimer(5000);

}





