void SetTextMode()

{

   if(textMode==0)

   {

      int index = 0;

      while( index < 10 )

      {

         HotSpot_Holder.EnableHotSpot(index);

         index++;

      }



      if(chrust==0 && woz)

      {

             Panorama_Holder.GoRight(2);   

             Sound_Holder.PlayDSound(0);

             Sprite_Holder.ContinueAnimation(0);

             Sprite_Holder.ContinueAnimation(1);

             woz=0;

      }



      playStatus = 0;

      Sound_Holder.Stop(5);

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(0,0,0,0);

   }

   else

   {

      Sound_Holder.Stop(0);



      int index = 0;

      while( index < 10 )

      {

         HotSpot_Holder.DisableHotSpot(index);

         index++;

      }



      playStatus = 1;   

      Sound_Holder.SetPlayDSoundParameters(0,-1000,0,0);

      Sound_Holder.PlayDSound(5);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

   }

}







