VOID HotSpot_Holder.LeftButtonClickOn(int rectID)

{

   switch(rectID)

   {

       case 0: 

         if(chrust==0 && woz)

         {

             Panorama_Holder.GoRight(2);   

             Sound_Holder.PlayDSound(0);

             Sprite_Holder.ContinueAnimation(0);

             Sprite_Holder.ContinueAnimation(1);

             woz=0;

         }

         break;

      case 1: 

         if(chrust==0 && woz)

         {

             Panorama_Holder.GoRight(2);   

             Sound_Holder.PlayDSound(0);

             Sprite_Holder.ContinueAnimation(0);

             Sprite_Holder.ContinueAnimation(1);

             woz=0;

         }                        

         break;

      case 2:

         Transparent_Video_Holder.Play(0,0);

         break; 

      case 3:

         if(woz)

         {

            if (patyk1)

            {

                Bitmap_Holder.HideBitmap(1);

                patyk1=0;

            }

            if (patyk2)

                Sound_Holder.PlayDSound(1);

            if ((patyk1==0)&&(patyk2==0)&&(chrust==0))

            {

                Sound_Holder.PlayDSound(2);

                Sprite_Holder.HideSprite(2);

                Bitmap_Holder.ShowBitmap(4);

                Bitmap_Holder.ShowBitmap(5);

                Bitmap_Holder.ShowBitmap(6);

                chrust=3;

            }             

         }

         break;

     case 4:

         if(woz)

         {

            if (patyk2)

            {

               Bitmap_Holder.HideBitmap(2);

               patyk2=0;

            }

            if (patyk1)

               Sound_Holder.PlayDSound(1);

            if ((patyk1==0)&&(patyk2==0)&&(chrust==0))

            {

               Sound_Holder.PlayDSound(2);

               Sprite_Holder.HideSprite(2);

               Bitmap_Holder.ShowBitmap(4);

               Bitmap_Holder.ShowBitmap(5);

               Bitmap_Holder.ShowBitmap(6);

               chrust=3;

            }             

            break;

         }

      case 5:

         Transparent_Video_Holder.Play(1,0);

         break; 

      case 6:

         Transparent_Video_Holder.Play(2,0);

         break; 

      case 9:      //chrust 1

         if(chrust==3)

         {

             Sound_Holder.PlayDSound(3);

             Sprite_Holder.ChangePhase(2,2);

             Sprite_Holder.ShowSprite(2);

             Bitmap_Holder.HideBitmap(5);

             chrust=2;

             SetCursor(0);

         }

         break;   

      case 8:   //chrust 2

         if(chrust==2)

         {

             Sound_Holder.PlayDSound(3);

             Sprite_Holder.ChangePhase(2,1);

             Bitmap_Holder.HideBitmap(6);

             chrust=1;

             SetCursor(0);

         }

         break;                                     

      case 7:   //chrust 3

         if(chrust==1)

         {

             Sound_Holder.PlayDSound(3);

             Sprite_Holder.ChangePhase(2,0);

             Bitmap_Holder.HideBitmap(4);

             chrust=0;

             Bitmap_Holder.ShowBitmap(1);

             Bitmap_Holder.ShowBitmap(2);

             patyk1=255;

             patyk2=255;                                    

             SetCursor(0);

         }

         break;  

   }

}



VOID Sound_Holder.EndPlaySound(int soundID)

{

   if(soundID==0)

   {

      Panorama_Holder.Stop();

      Sprite_Holder.StopAnimation(0);

      Sprite_Holder.StopAnimation(1);

      woz=255;

   }



   if(soundID==5 && textMode)

   { 

      playStatus=1;

      Text_Holder.EnableMouse(0);

      Text_Holder.PlaySynchroText(0);

   }

}





void HotSpot_Holder.MouseMoveIn(int rectID)

{

   switch(rectID)

   {

      case 0:

      case 1:

         if(woz==0 || chrust)   break;

         SetCursor(1);

         break;

      case 3:

      case 4:

         if(woz==0 || chrust)   break;

         SetCursor(1);

         break;

      case 7:

         if(woz && chrust>0)   SetCursor(1);

         break;

      case 8:

         if(woz && chrust>1)   SetCursor(1);

         break;

      case 9:

         if(woz && chrust>2)   SetCursor(1);

         break;

      default:

         SetCursor(1);

         break;

   }

}





void HotSpot_Holder.MouseMoveOut(int rectID)

{

   SetCursor(0);

}





void OnKeyDown(UINT nChar)

{

        //Add your command handler code here

   LoadPage("wyborw.bdf");

}



